#include <stdio.h>
#include <stdint.h>

const int MOD = 1000000007;

int countSubsets(int N, int K, int B) {
    int count = 0;
    for (uint64_t mask = 0; mask < (1ULL << N); mask++) {
        if (__builtin_popcountll(mask) == K) {
            uint64_t xorSum = 0;
            for (int i = 0; i < N; i++) {
                if ((mask & (1ULL << i)) != 0) {
                    xorSum ^= i;
                }
            }
            if (__builtin_popcountll(xorSum) == B) {
                count = (count + 1) % MOD;
            }
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N, K, B;
        scanf("%d %d %d", &N, &K, &B);
        printf("%d\n", countSubsets(N, K, B));
    }
    return 0;
}

