import sys

MOD = 1000000007

def countSubsets(N, K, B):
    count = 0
    for mask in range(1 << N):
        if bin(mask).count('1') == K:
            xorSum = 0
            for i in range(N):
                if (mask & (1 << i)) != 0:
                    xorSum ^= i
            if bin(xorSum).count('1') == B:
                count = (count + 1) % MOD
    return count

