        if (countBits(mask) === K) {
            let xorSum = 0;
            for (let i = 0; i < N; i++) {
                if ((mask & (1 << i)) !== 0) {
                    xorSum ^= i;
                }
            }
            if (countBits(xorSum) === B) {
                count = (count + 1) % 1000000007;
            }
        }
    }
    return count;
